-- Generated by AutomateDV (formerly known as dbtvault)

    

WITH source_data AS (
    SELECT a.COMPANY_PK, a.COMPANY_HASHDIFF, a.COMPANY_NM, a.EFFECTIVE_FROM, a.LOAD_DATE, a.RECORD_SOURCE
    FROM S45969_DBT_DB.S45969_DBT_AH_SCHEMA.v_stg_company AS a
    WHERE a.COMPANY_PK IS NOT NULL
),

latest_records AS (
    SELECT a.COMPANY_PK, a.COMPANY_HASHDIFF, a.LOAD_DATE
    FROM (
        SELECT current_records.COMPANY_PK, current_records.COMPANY_HASHDIFF, current_records.LOAD_DATE,
            RANK() OVER (
               PARTITION BY current_records.COMPANY_PK
               ORDER BY current_records.LOAD_DATE DESC
            ) AS rank
        FROM S45969_DBT_DB.S45969_DBT_AH_SCHEMA.sat_company AS current_records
            JOIN (
                SELECT DISTINCT source_data.COMPANY_PK
                FROM source_data
            ) AS source_records
                ON current_records.COMPANY_PK = source_records.COMPANY_PK
    ) AS a
    WHERE a.rank = 1
),

records_to_insert AS (
    SELECT DISTINCT stage.COMPANY_PK, stage.COMPANY_HASHDIFF, stage.COMPANY_NM, stage.EFFECTIVE_FROM, stage.LOAD_DATE, stage.RECORD_SOURCE
    FROM source_data AS stage
    LEFT JOIN latest_records
    ON latest_records.COMPANY_PK = stage.COMPANY_PK
        AND latest_records.COMPANY_HASHDIFF = stage.COMPANY_HASHDIFF
    WHERE latest_records.COMPANY_HASHDIFF IS NULL
)

SELECT * FROM records_to_insert